import { useMemo, useState } from 'react';
import { useExpenseContext } from '../context/ExpenseContext';
import InsightCard from '../components/widgets/InsightCard';
import { Wallet, TrendingUp, ArrowUpRight, ArrowDownRight, Lightbulb } from 'lucide-react';
import { format, parseISO, subMonths, isSameMonth } from 'date-fns';
import {
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  PieChart, Pie, Cell, Legend
} from 'recharts';

const COLORS = ['#4f46e5', '#8b5cf6', '#ec4899', '#f43f5e', '#f97316', '#eab308', '#22c55e', '#06b6d4'];

export default function Dashboard() {
  const { transactions } = useExpenseContext();
  const [selectedMonth, setSelectedMonth] = useState<number>(0); // 0 = current, 1 = last month, -1 = all time

  const filteredTransactions = useMemo(() => {
    if (selectedMonth === -1) return transactions;
    const targetMonth = subMonths(new Date(), selectedMonth);
    return transactions.filter(t => isSameMonth(parseISO(t.date), targetMonth));
  }, [transactions, selectedMonth]);

  const { totalIncome, totalExpense, balance, categoryData, chartData, highestExpenseCategory } = useMemo(() => {
    let inc = 0;
    let exp = 0;
    const catMap: Record<string, number> = {};
    const dateMap: Record<string, { income: number; expense: number }> = {};

    filteredTransactions.forEach(t => {
      const amount = Number(t.amount);
      if (t.type === 'INCOME') {
        inc += amount;
      } else {
        exp += amount;
        catMap[t.category] = (catMap[t.category] || 0) + amount;
      }

      const dateStr = format(parseISO(t.date), 'MMM dd');
      if (!dateMap[dateStr]) dateMap[dateStr] = { income: 0, expense: 0 };
      if (t.type === 'INCOME') dateMap[dateStr].income += amount;
      else dateMap[dateStr].expense += amount;
    });

    const categoryDataArray = Object.entries(catMap)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value);

    // Cumulative balance for chart
    let runningBalance = 0;
    const chartDataArray = Object.entries(dateMap)
      // Sort by date chronologically for the chart
      .sort((a, b) => new Date(`${a[0]} ${new Date().getFullYear()}`).getTime() - new Date(`${b[0]} ${new Date().getFullYear()}`).getTime())
      .map(([date, data]) => {
        runningBalance += (data.income - data.expense);
        return {
          date,
          income: data.income,
          expense: data.expense,
          balance: runningBalance
        };
      });

    const highest = categoryDataArray.length > 0 ? categoryDataArray[0] : null;

    return {
      totalIncome: inc,
      totalExpense: exp,
      balance: inc - exp,
      categoryData: categoryDataArray,
      chartData: chartDataArray,
      highestExpenseCategory: highest
    };
  }, [filteredTransactions]);

  const formatter = new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' });

  return (
    <div className="space-y-8 animate-fade-in pb-12">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Dashboard Overview</h1>
          <p className="text-foreground/60 mt-1">Track, analyze, and manage your financial metrics.</p>
        </div>

        <select
          value={selectedMonth}
          onChange={(e) => setSelectedMonth(Number(e.target.value))}
          className="bg-card backdrop-blur-md border border-border text-foreground text-sm rounded-xl px-4 py-2 shadow-sm focus:ring-primary focus:border-primary outline-none"
        >
          <option value="-1">All Time</option>
          <option value="0">This Month</option>
          <option value="1">Last Month</option>
          <option value="2">2 Months Ago</option>
        </select>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <InsightCard
          title="Total Balance"
          value={formatter.format(balance)}
          icon={<Wallet className="w-6 h-6" />}
          trend={balance >= 0 ? 'up' : 'down'}
          trendValue={balance >= 0 ? '+ Positive' : '- Warning'}
          className="border-t-4 border-t-primary"
        />
        <InsightCard
          title="Total Income"
          value={formatter.format(totalIncome)}
          icon={<ArrowUpRight className="w-6 h-6" />}
          trend="up"
          trendValue="Revenue"
          className="border-t-4 border-t-success"
        />
        <InsightCard
          title="Total Expenses"
          value={formatter.format(totalExpense)}
          icon={<ArrowDownRight className="w-6 h-6" />}
          trend="down"
          trendValue="Outflow"
          className="border-t-4 border-t-destructive"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Trend Chart */}
        <div className="glass-panel p-6 lg:col-span-2 flex flex-col min-h-[400px]">
          <h3 className="text-lg font-semibold mb-6 flex items-center gap-2">
            <TrendingUp className="w-5 h-5 text-primary" /> Cashflow Trend
          </h3>
          <div className="flex-1 w-full relative">
            {chartData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={chartData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                  <defs>
                    <linearGradient id="colorInc" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="rgb(var(--success))" stopOpacity={0.3}/>
                      <stop offset="95%" stopColor="rgb(var(--success))" stopOpacity={0}/>
                    </linearGradient>
                    <linearGradient id="colorExp" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="rgb(var(--destructive))" stopOpacity={0.3}/>
                      <stop offset="95%" stopColor="rgb(var(--destructive))" stopOpacity={0}/>
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="rgb(var(--border))" opacity={0.5} />
                  <XAxis dataKey="date" stroke="currentColor" fontSize={12} tickLine={false} axisLine={false} opacity={0.5} />
                  <YAxis stroke="currentColor" fontSize={12} tickLine={false} axisLine={false} opacity={0.5} tickFormatter={(val) => `$${val}`} />
                  <Tooltip 
                    contentStyle={{ borderRadius: '12px', border: '1px solid rgb(var(--border) / 0.6)', background: 'rgb(var(--card) / 0.7)', backdropFilter: 'blur(12px)', color: 'rgb(var(--foreground))' }}
                    itemStyle={{ color: 'rgb(var(--foreground))' }}
                  />
                  <Area type="monotone" dataKey="income" stroke="rgb(var(--success))" fillOpacity={1} fill="url(#colorInc)" strokeWidth={3} />
                  <Area type="monotone" dataKey="expense" stroke="rgb(var(--destructive))" fillOpacity={1} fill="url(#colorExp)" strokeWidth={3} />
                </AreaChart>
              </ResponsiveContainer>
            ) : (
              <div className="absolute inset-0 flex items-center justify-center text-foreground/50">
                No data available for this period
              </div>
            )}
          </div>
        </div>

        {/* Category Breakdown */}
        <div className="glass-panel p-6 flex flex-col min-h-[400px]">
          <h3 className="text-lg font-semibold mb-6">Spending Breakdown</h3>
          <div className="flex-1 w-full relative -mt-4">
            {categoryData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={categoryData}
                    cx="50%"
                    cy="50%"
                    innerRadius={80}
                    outerRadius={110}
                    paddingAngle={5}
                    dataKey="value"
                    stroke="none"
                  >
                    {categoryData.map((_, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip 
                    formatter={(value: any) => formatter.format(Number(value))}
                    contentStyle={{ borderRadius: '12px', border: '1px solid rgb(var(--border) / 0.6)', background: 'rgb(var(--card) / 0.7)', color: 'rgb(var(--foreground))' }}
                  />
                  <Legend verticalAlign="bottom" height={36} iconType="circle" />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="absolute inset-0 flex items-center justify-center text-foreground/50">
                No expenses recorded
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Dynamic Insights / Observation AI Simulator */}
      <div className="glass-panel p-6 bg-gradient-to-r from-primary/10 to-accent/10 border-l-4 border-l-primary flex items-start gap-4">
        <div className="bg-primary/20 p-3 rounded-full mt-1">
          <Lightbulb className="w-6 h-6 text-primary" />
        </div>
        <div>
          <h3 className="text-lg font-bold">Key Insight</h3>
          <p className="text-foreground/80 mt-1 leading-relaxed">
            {highestExpenseCategory 
              ? `Your highest spending category this period is '${highestExpenseCategory.name}' at ${formatter.format(highestExpenseCategory.value)}. Consider creating a specialized budget targeted at this category to maximize your savings.`
              : 'Add some transactions to receive personalized data-driven insights here.'}
            {totalIncome > totalExpense 
              ? ` Great job keeping expenses (${formatter.format(totalExpense)}) below your income (${formatter.format(totalIncome)})! Keep this up.`
              : totalIncome > 0 ? ` Caution: Your expenses are exceeding your income by ${formatter.format(totalExpense - totalIncome)}.` : ''}
          </p>
        </div>
      </div>
    </div>
  );
}

import { useState, useMemo } from 'react';
import { useExpenseContext } from '../context/ExpenseContext';
import TransactionForm from '../components/transactions/TransactionForm';
import type { Transaction } from '../types';
import { Plus, Search, Filter, ArrowDownUp, Edit2, Trash2 } from 'lucide-react';
import { format, parseISO } from 'date-fns';

export default function TransactionsPage() {
  const { transactions, role, addTransaction, updateTransaction, deleteTransaction } = useExpenseContext();

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);

  // Filters
  const [search, setSearch] = useState('');
  const [typeFilter, setTypeFilter] = useState<'ALL' | 'INCOME' | 'EXPENSE'>('ALL');
  const [categoryFilter, setCategoryFilter] = useState('ALL');

  // Sort
  const [sortField, setSortField] = useState<'date' | 'amount'>('date');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');

  const formatter = new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' });

  // Get unique categories for filter
  const categories = useMemo(() => {
    const cats = new Set(transactions.map(t => t.category));
    return ['ALL', ...Array.from(cats)].sort();
  }, [transactions]);

  const filteredAndSorted = useMemo(() => {
    let result = transactions;

    if (search) {
      const q = search.toLowerCase();
      result = result.filter(t => 
        t.description.toLowerCase().includes(q) || 
        t.category.toLowerCase().includes(q) ||
        t.amount.toString().includes(q)
      );
    }

    if (typeFilter !== 'ALL') {
      result = result.filter(t => t.type === typeFilter);
    }

    if (categoryFilter !== 'ALL') {
      result = result.filter(t => t.category === categoryFilter);
    }

    result.sort((a, b) => {
      let comparison = 0;
      if (sortField === 'date') {
        comparison = new Date(a.date).getTime() - new Date(b.date).getTime();
      } else {
        comparison = a.amount - b.amount;
      }
      return sortOrder === 'asc' ? comparison : -comparison;
    });

    return result;
  }, [transactions, search, typeFilter, categoryFilter, sortField, sortOrder]);

  const handleEdit = (tx: Transaction) => {
    setEditingTx(tx);
    setIsFormOpen(true);
  };

  const handleDelete = (id: string) => {
    if (window.confirm("Are you sure you want to delete this transaction?")) {
      deleteTransaction(id);
    }
  };

  const handleFormSubmit = (data: Omit<Transaction, 'id'>) => {
    if (editingTx) {
      updateTransaction(editingTx.id, data);
    } else {
      addTransaction(data);
    }
    setEditingTx(null);
  };

  const toggleSort = (field: 'date' | 'amount') => {
    if (sortField === field) {
      setSortOrder(prev => prev === 'asc' ? 'desc' : 'asc');
    } else {
      setSortField(field);
      setSortOrder('desc');
    }
  };

  return (
    <div className="space-y-6 animate-fade-in pb-12">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Transactions</h1>
          <p className="text-foreground/60 mt-1">Manage and filter your financial records.</p>
        </div>

        {role === 'ADMIN' && (
          <button 
            onClick={() => { setEditingTx(null); setIsFormOpen(true); }}
            className="btn btn-primary px-6"
          >
            <Plus className="w-5 h-5 mr-2" />
            Add Transaction
          </button>
        )}
      </div>

      <div className="glass-panel p-4 flex flex-col sm:flex-row gap-4 items-center z-10 relative">
        <div className="relative flex-1 w-full sm:w-auto">
          <Search className="absolute left-3 top-2.5 w-5 h-5 text-foreground/50" />
          <input 
            type="text" 
            placeholder="Search descriptions, amounts..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-10 pr-4 py-2 bg-background border border-border rounded-xl focus:ring-2 focus:ring-primary outline-none transition-all"
          />
        </div>

        <div className="flex gap-2 w-full sm:w-auto overflow-x-auto pb-1 sm:pb-0">
          <div className="flex items-center gap-2 px-3 py-2 bg-background border border-border rounded-xl whitespace-nowrap">
            <Filter className="w-4 h-4 text-foreground/50" />
            <select 
              value={typeFilter} 
              onChange={(e) => setTypeFilter(e.target.value as any)}
              className="bg-transparent border-none outline-none text-sm font-medium focus:ring-0"
            >
              <option value="ALL">All Types</option>
              <option value="INCOME">Income</option>
              <option value="EXPENSE">Expense</option>
            </select>
          </div>

          <div className="flex items-center gap-2 px-3 py-2 bg-background border border-border rounded-xl whitespace-nowrap">
            <select 
              value={categoryFilter} 
              onChange={(e) => setCategoryFilter(e.target.value)}
              className="bg-transparent border-none outline-none text-sm font-medium focus:ring-0 max-w-[120px]"
            >
              {categories.map(c => <option key={c} value={c}>{c === 'ALL' ? 'All Categories' : c}</option>)}
            </select>
          </div>
        </div>
      </div>

      <div className="glass-panel overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm whitespace-nowrap">
            <thead className="bg-secondary/40 text-foreground/70 uppercase text-xs font-semibold border-b border-border">
              <tr>
                <th className="px-6 py-4 cursor-pointer hover:text-foreground transition-colors group" onClick={() => toggleSort('date')}>
                  <div className="flex items-center gap-2">
                    Date
                    <ArrowDownUp className={`w-3 h-3 transition-opacity ${sortField === 'date' ? 'opacity-100 text-primary' : 'opacity-0 group-hover:opacity-50'}`} />
                  </div>
                </th>
                <th className="px-6 py-4">Description</th>
                <th className="px-6 py-4">Category</th>
                <th className="px-6 py-4 cursor-pointer hover:text-foreground transition-colors group" onClick={() => toggleSort('amount')}>
                  <div className="flex items-center gap-2 justify-end">
                    Amount
                    <ArrowDownUp className={`w-3 h-3 transition-opacity ${sortField === 'amount' ? 'opacity-100 text-primary' : 'opacity-0 group-hover:opacity-50'}`} />
                  </div>
                </th>
                {role === 'ADMIN' && <th className="px-6 py-4 text-center">Actions</th>}
              </tr>
            </thead>
            <tbody className="divide-y divide-border/50">
              {filteredAndSorted.length > 0 ? (
                filteredAndSorted.map((tx) => (
                  <tr key={tx.id} className="hover:bg-secondary/20 transition-colors group">
                    <td className="px-6 py-4 font-medium">{format(parseISO(tx.date), 'MMM dd, yyyy')}</td>
                    <td className="px-6 py-4 text-foreground/80">{tx.description}</td>
                    <td className="px-6 py-4">
                      <span className="px-2.5 py-1 bg-secondary/50 rounded-lg text-xs font-medium">
                        {tx.category}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <span className={`font-semibold ${tx.type === 'INCOME' ? 'text-success' : 'text-destructive'}`}>
                        {tx.type === 'INCOME' ? '+' : '-'}{formatter.format(tx.amount)}
                      </span>
                    </td>
                    {role === 'ADMIN' && (
                      <td className="px-6 py-4 text-center">
                        <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button onClick={() => handleEdit(tx)} className="p-1.5 text-foreground/50 hover:text-primary bg-background rounded-lg border border-border/50 hover:border-primary/50 transition-colors" title="Edit">
                            <Edit2 className="w-4 h-4" />
                          </button>
                          <button onClick={() => handleDelete(tx.id)} className="p-1.5 text-foreground/50 hover:text-destructive bg-background rounded-lg border border-border/50 hover:border-destructive/50 transition-colors" title="Delete">
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </div>
                      </td>
                    )}
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={role === 'ADMIN' ? 5 : 4} className="px-6 py-12 text-center text-foreground/50">
                    No transactions found matching your criteria.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {isFormOpen && (
        <TransactionForm 
          onClose={() => {
            setIsFormOpen(false);
            setEditingTx(null);
          }} 
          onSubmit={handleFormSubmit}
          initialData={editingTx}
        />
      )}
    </div>
  );
}
